def calculate_average_effectiveness(feedback, treatment_name):
    # Initialize a list to collect effectiveness ratings for the specified treatment
    effectiveness_ratings = []

    # Iterate through each patient's feedback
    for patient in feedback:
        if treatment_name in patient["treatments"]:
            effectiveness_ratings.append(patient["treatments"][treatment_name])

    # Calculate the average effectiveness
    if effectiveness_ratings:
        average = sum(effectiveness_ratings) / len(effectiveness_ratings)
        return round(average, 2)
    else:
        return 0.0

